import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Terms.css";

const RULES = [
  {
    icon: "🚫",
    title: "No Inappropriate Content",
    desc: "Do not send sexual, violent, hateful, or offensive messages. This includes images, videos, and voice messages.",
  },
  {
    icon: "🔒",
    title: "Respect Privacy",
    desc: "Do not share other people's personal information, photos, or private conversations without their consent.",
  },
  {
    icon: "🤝",
    title: "No Harassment or Bullying",
    desc: "Treat everyone with respect. Harassment, threats, and bullying of any kind will result in an immediate ban.",
  },
  {
    icon: "🛡️",
    title: "No Spam or Scams",
    desc: "Do not send unsolicited messages, phishing links, or attempt to deceive or defraud other users.",
  },
  {
    icon: "👶",
    title: "Age Requirement",
    desc: "You must be at least 13 years old to use PeerSync. Do not share content inappropriate for minors.",
  },
  {
    icon: "⚖️",
    title: "Legal Compliance",
    desc: "Do not use PeerSync for any illegal activities, including sharing copyrighted material without permission.",
  },
  {
    icon: "✅",
    title: "Your Responsibility",
    desc: "You are responsible for all activity on your account. Keep your password safe and do not share your account.",
  },
  {
    icon: "🔧",
    title: "Enforcement",
    desc: "Violations may result in content removal, account suspension, or permanent ban without prior notice.",
  },
];

export default function Terms() {
  const [scrolled, setScrolled] = useState(false);
  const [checked, setChecked] = useState(false);
  const navigate = useNavigate();

  const handleScroll = (e) => {
    const el = e.target;
    const bottom = el.scrollHeight - el.scrollTop <= el.clientHeight + 40;
    if (bottom) setScrolled(true);
  };

  const handleAccept = () => {
    if (!checked) return;
    localStorage.setItem("terms_accepted", "true");
    navigate("/");
  };

  return (
    <div className="terms-page">
      <div className="terms-card">

        {/* Header */}
        <div className="terms-header">
          <div className="terms-logo">⚖️</div>
          <h1 className="terms-title">Community Guidelines</h1>
          <p className="terms-sub">Please read and accept our terms before using PeerSync</p>
        </div>

        {/* Scrollable rules */}
        <div className="terms-scroll" onScroll={handleScroll}>
          <p className="terms-intro">
            Welcome to PeerSync! To keep this a safe and respectful space for everyone,
            you must agree to follow these community guidelines. Violating these rules
            may result in your account being suspended or permanently banned.
          </p>

          <div className="terms-rules">
            {RULES.map((rule, i) => (
              <div key={i} className="terms-rule">
                <div className="rule-icon">{rule.icon}</div>
                <div className="rule-content">
                  <h3 className="rule-title">{rule.title}</h3>
                  <p className="rule-desc">{rule.desc}</p>
                </div>
              </div>
            ))}
          </div>

          <div className="terms-footer-text">
            <p>
              These guidelines are subject to change. Continued use of PeerSync
              constitutes acceptance of any updates. Last updated: March 2026.
            </p>
          </div>
        </div>

        {/* Scroll hint */}
        {!scrolled && (
          <div className="scroll-hint">↓ Scroll down to read all guidelines</div>
        )}

        {/* Accept section */}
        <div className="terms-accept">
          <label className={`checkbox-row ${!scrolled ? "disabled" : ""}`}>
            <div
              className={`custom-checkbox ${checked ? "checked" : ""} ${!scrolled ? "disabled" : ""}`}
              onClick={() => scrolled && setChecked(!checked)}
            >
              {checked && <span>✓</span>}
            </div>
            <span className="checkbox-label">
              I have read and agree to the Community Guidelines and Terms of Service
            </span>
          </label>

          <button
            className={`terms-btn ${checked ? "active" : ""}`}
            onClick={handleAccept}
            disabled={!checked}
          >
            {checked ? "Accept & Continue →" : scrolled ? "Check the box to continue" : "Read all guidelines first"}
          </button>
        </div>

      </div>
    </div>
  );
}
